import{_ as t,c as e,o,ag as l}from"./chunks/framework.DK1-H3E1.js";const u=JSON.parse('{"title":"MCP：Model Context Protocol 入门","description":"","frontmatter":{"order":10},"headers":[],"relativePath":"ai/mcp.md","filePath":"ai/mcp.md","lastUpdated":1772197851000}'),a={name:"ai/mcp.md"};function s(i,r,n,d,h,c){return o(),e("div",null,r[0]||(r[0]=[l('<h1 id="mcp-model-context-protocol-入门" tabindex="-1">MCP：Model Context Protocol 入门 <a class="header-anchor" href="#mcp-model-context-protocol-入门" aria-label="Permalink to &quot;MCP：Model Context Protocol 入门&quot;">​</a></h1><blockquote><p>📅 主题：工具与资源的标准化协议、MCP 服务与客户端</p></blockquote><h2 id="一、什么是-mcp" tabindex="-1">一、什么是 MCP <a class="header-anchor" href="#一、什么是-mcp" aria-label="Permalink to &quot;一、什么是 MCP&quot;">​</a></h2><p><strong>MCP（Model Context Protocol，模型上下文协议）</strong> 是一套开放协议，用于<strong>标准化 AI 应用与外部「能力」之间的连接方式</strong>。这里的「能力」主要包括两类：</p><ul><li><strong>工具（Tools）</strong>：可被调用的操作，例如执行代码、调用 API、查询数据库、读写文件等，有输入参数和返回结果。</li><li><strong>资源（Resources）</strong>：可被读取的数据源，例如文件、数据库表结构、配置等，通过 URI 标识，支持按需拉取内容到模型上下文。</li></ul><p>在 MCP 里：</p><ul><li><strong>MCP Server（MCP 服务）</strong>：暴露一组工具和/或资源，实现具体逻辑（如连接数据库、调用 GitHub API）。</li><li><strong>MCP Client（MCP 客户端）</strong>：通常是 AI 应用（如 Cursor、Claude Desktop、自建 Agent），发现并连接这些 Server，把工具和资源「注入」到模型的上下文中，让模型可以按需调用工具、读取资源。</li></ul><p>一句话：<strong>MCP 定义了「AI 应用如何发现、连接和使用外部工具与资源」的通用约定</strong>，避免每个应用、每个能力都各自造一套对接方式。</p><hr><h2 id="二、为什么需要-mcp" tabindex="-1">二、为什么需要 MCP <a class="header-anchor" href="#二、为什么需要-mcp" aria-label="Permalink to &quot;二、为什么需要 MCP&quot;">​</a></h2><p>在没有统一协议之前：</p><ul><li>每个 AI 产品各自定义「工具」的格式、调用方式、认证方式。</li><li>开发者想给多个 AI 应用提供同一能力（如「查公司文档」「执行 SQL」），需要为每个应用写一套适配。</li><li>工具与资源的形态不统一，难以复用和组合。</li></ul><p>MCP 的目标是：</p><ul><li><strong>一次实现，多处使用</strong>：写一个 MCP Server（如「文件系统 Server」「GitHub Server」），任何兼容 MCP 的客户端都能连接使用。</li><li><strong>统一抽象</strong>：工具 = 名称 + 描述 + 参数 schema；资源 = URI + 类型 + 可选内容。客户端用同一套模型与 UI 展示、调用。</li><li><strong>生态与可扩展</strong>：社区可以贡献各类 MCP Server（数据库、浏览器、日历、邮件等），用户按需启用，扩展 AI 的能力边界。</li></ul><hr><h2 id="三、核心概念" tabindex="-1">三、核心概念 <a class="header-anchor" href="#三、核心概念" aria-label="Permalink to &quot;三、核心概念&quot;">​</a></h2><h3 id="_3-1-工具-tools" tabindex="-1">3.1 工具（Tools） <a class="header-anchor" href="#_3-1-工具-tools" aria-label="Permalink to &quot;3.1 工具（Tools）&quot;">​</a></h3><ul><li><strong>定义</strong>：Server 暴露的「可执行动作」，每个工具有名称、描述和参数 schema（如 JSON Schema）。</li><li><strong>使用流程</strong>：客户端把工具列表提供给模型；模型决定调用哪个工具、传什么参数；客户端把调用请求发给 Server；Server 执行后返回结果；客户端把结果交回模型继续推理或生成。</li><li><strong>示例</strong>：<code>read_file</code>（path）、<code>run_sql</code>（query, db）、<code>search_web</code>（query）等。</li></ul><h3 id="_3-2-资源-resources" tabindex="-1">3.2 资源（Resources） <a class="header-anchor" href="#_3-2-资源-resources" aria-label="Permalink to &quot;3.2 资源（Resources）&quot;">​</a></h3><ul><li><strong>定义</strong>：Server 暴露的「可读数据」，用 URI 标识（如 <code>file:///path/to/doc.md</code>、<code>db://schema/users</code>）。</li><li><strong>使用流程</strong>：客户端可列出资源、按 URI 请求内容；Server 返回资源内容（如文本、Base64 等）；客户端将内容注入模型上下文，供模型参考。</li><li><strong>与 RAG 的区别</strong>：RAG 一般是「用户问题 → 检索 → 片段进上下文」；MCP 资源是「按 URI 拉取指定资源内容进上下文」，更偏结构化、按需加载。</li></ul><h3 id="_3-3-prompts-可选" tabindex="-1">3.3 Prompts（可选） <a class="header-anchor" href="#_3-3-prompts-可选" aria-label="Permalink to &quot;3.3 Prompts（可选）&quot;">​</a></h3><ul><li>部分 MCP 实现还支持 <strong>Prompts</strong>：Server 预定义一批「提示模板」，客户端可以列出并请求渲染后的提示（如「用当前项目信息生成周报」），便于标准化常用任务。</li></ul><hr><h2 id="四、架构与通信" tabindex="-1">四、架构与通信 <a class="header-anchor" href="#四、架构与通信" aria-label="Permalink to &quot;四、架构与通信&quot;">​</a></h2><h3 id="_4-1-客户端–服务端" tabindex="-1">4.1 客户端–服务端 <a class="header-anchor" href="#_4-1-客户端–服务端" aria-label="Permalink to &quot;4.1 客户端–服务端&quot;">​</a></h3><ul><li><strong>Server</strong>：常以进程形式运行，启动后监听或等待连接；实现「列出工具/资源」「执行工具」「读取资源」等接口。</li><li><strong>Client</strong>：AI 应用内嵌或单独进程，负责发现 Server、建立连接、转发模型的工具调用与资源请求，并把结果反馈给模型。</li></ul><h3 id="_4-2-传输方式" tabindex="-1">4.2 传输方式 <a class="header-anchor" href="#_4-2-传输方式" aria-label="Permalink to &quot;4.2 传输方式&quot;">​</a></h3><ul><li><strong>stdio</strong>：同一台机器上，Client 启动 Server 子进程，通过标准输入/输出交换 JSON-RPC 消息。简单、易调试，适合本地开发。</li><li><strong>SSE（Server-Sent Events）</strong>：基于 HTTP，Server 暴露端点，Client 通过 HTTP 请求建立 SSE 连接并收发消息。适合远程、多实例部署。</li></ul><p>协议层一般是 <strong>JSON-RPC 2.0</strong>：请求与响应都是 JSON，包含 method（如 <code>tools/call</code>、<code>resources/read</code>）、params、id 等字段。</p><h3 id="_4-3-安全与权限" tabindex="-1">4.3 安全与权限 <a class="header-anchor" href="#_4-3-安全与权限" aria-label="Permalink to &quot;4.3 安全与权限&quot;">​</a></h3><ul><li>连接前可做<strong>认证与授权</strong>（例如 Token、API Key），避免未授权访问。</li><li>Client 侧可限制「允许连接哪些 Server」「允许调用哪些工具」，避免模型滥用敏感能力。</li><li>生产环境中通常会对网络、进程边界做隔离与审计。</li></ul><hr><h2 id="五、mcp-与-skills、rag、agent-的关系" tabindex="-1">五、MCP 与 Skills、RAG、Agent 的关系 <a class="header-anchor" href="#五、mcp-与-skills、rag、agent-的关系" aria-label="Permalink to &quot;五、MCP 与 Skills、RAG、Agent 的关系&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>角色</th><th>与 MCP 的关系</th></tr></thead><tbody><tr><td><strong>MCP</strong></td><td>定义「有哪些工具/资源、如何调用/读取」</td><td>提供能力接口的标准协议</td></tr><tr><td><strong>Skills / Agent Skills</strong></td><td>定义「在什么场景、按什么步骤使用能力」</td><td>Skills 描述「何时用哪个 MCP 工具/资源、怎么用」；MCP 提供能力，Skills 提供用法</td></tr><tr><td><strong>RAG</strong></td><td>检索知识库并注入上下文</td><td>可与 MCP 资源结合：资源提供「可读数据源」，RAG 流程决定「检索哪些、如何注入」；也可由 MCP 工具封装检索 API</td></tr><tr><td><strong>Agent</strong></td><td>决策与编排</td><td>Agent 通过 MCP Client 获取工具与资源列表，在推理中决定调用工具、读取资源，并处理返回结果</td></tr></tbody></table><p>因此：<strong>MCP 是能力层协议；Skills 是用法层；RAG 是检索与注入策略；Agent 是使用这些能力的智能体</strong>。四者配合，形成「标准能力接口 + 可复用用法 + 检索策略 + 自主决策」的完整链路。</p><hr><h2 id="六、实践-使用与开发-mcp" tabindex="-1">六、实践：使用与开发 MCP <a class="header-anchor" href="#六、实践-使用与开发-mcp" aria-label="Permalink to &quot;六、实践：使用与开发 MCP&quot;">​</a></h2><h3 id="_6-1-作为用户-客户端" tabindex="-1">6.1 作为用户 / 客户端 <a class="header-anchor" href="#_6-1-作为用户-客户端" aria-label="Permalink to &quot;6.1 作为用户 / 客户端&quot;">​</a></h3><ul><li>在支持 MCP 的应用（如 Cursor、Claude Desktop）中，配置要连接的 MCP Server（名称、启动命令或 URL、环境变量等）。</li><li>应用启动后会发现 Server 暴露的工具与资源，并在对话或 Agent 中展示「可用工具」「可读资源」，模型即可按需调用或拉取。</li><li>可同时连接多个 Server，扩展不同领域能力（文件、数据库、浏览器、日历等）。</li></ul><h3 id="_6-2-作为开发者-server-端" tabindex="-1">6.2 作为开发者 / Server 端 <a class="header-anchor" href="#_6-2-作为开发者-server-端" aria-label="Permalink to &quot;6.2 作为开发者 / Server 端&quot;">​</a></h3><ul><li>实现 MCP 协议规定的接口：<strong>初始化</strong>、<strong>列出工具</strong>、<strong>调用工具</strong>、<strong>列出资源</strong>、<strong>读取资源</strong>（以及可选 Prompts）。</li><li>工具实现中完成真实逻辑（调 API、查库、读写文件），并把结果按协议格式返回。</li><li>选择传输方式（stdio 或 SSE），编写配置说明（如何启动、所需环境变量），便于用户在其他客户端中复用。</li></ul><h3 id="_6-3-生态与示例" tabindex="-1">6.3 生态与示例 <a class="header-anchor" href="#_6-3-生态与示例" aria-label="Permalink to &quot;6.3 生态与示例&quot;">​</a></h3><ul><li>官方与社区提供多种 MCP Server 示例：文件系统、Git、GitHub、数据库、Slack、Notion 等。</li><li>查阅 <a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol</a> 文档与 SDK（如 TypeScript/JavaScript、Python）可快速搭建 Server 或集成 Client。</li></ul><hr><h2 id="七、小结" tabindex="-1">七、小结 <a class="header-anchor" href="#七、小结" aria-label="Permalink to &quot;七、小结&quot;">​</a></h2><ol><li><strong>MCP</strong> 是「模型上下文协议」，用于标准化 AI 应用与<strong>工具</strong>、<strong>资源</strong>之间的连接方式；Server 暴露能力，Client 发现并调用/读取，供模型使用。</li><li><strong>工具</strong>：可执行操作，有名称、描述与参数；<strong>资源</strong>：可读数据，用 URI 标识；可选 <strong>Prompts</strong> 提供预定义提示模板。</li><li><strong>架构</strong>：Client–Server，常用 stdio（本地）或 SSE（远程），基于 JSON-RPC 通信；需考虑认证、权限与安全。</li><li><strong>与 Skills、RAG、Agent</strong>：MCP 提供能力接口；Skills 规定用法与编排；RAG 负责检索与注入策略；Agent 基于 MCP 能力做决策与执行。</li><li><strong>实践</strong>：用户侧配置并连接 MCP Server；开发者侧实现协议接口、选择传输方式并编写配置，即可融入现有 MCP 生态。</li></ol>',46)]))}const P=t(a,[["render",s]]);export{u as __pageData,P as default};
